parameters.text:
=Тікет від клієнта:

From: {{ $json.from_email }}
Subject: {{ $json.subject }}
Body: {{ $json.body }}
Thread ID: {{ $json.thread_link }}

=:rotating_light: *Новий тікет — {{ $json.output.priority }}*

*Власник:* {{ $json.output.owner }}
*Категорія:* {{ $json.output.owner }}
*SLA:* {{ $json.output.sla_minutes }} хв (до {{ $json.output.sla_deadline }})
*Sentiment:* {{ $json.output.customer_sentiment }}

*Тема:* {{ $('Collect Ticket Context').item.json.subject }}
*Від:* {{ $('Collect Ticket Context').item.json.from_email }}

*Що сталось:* {{ $json.output.summary }}

*Чому такий пріоритет:*
_{{ $json.output.reasoning }}_

<{{ $json.output.thread_link }}|→ Відкрити thread>

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "category": {
      "type": "string",
      "enum": ["order_delivery", "payment", "quality", "installation", "tech", "consultation"]
    },
    "priority": {
      "type": "string",
      "enum": ["P1", "P2", "P3", "P4"]
    },
    "owner": {
      "type": "string",
      "enum": ["irina_logistics", "oleg_founder", "maksym_support", "dmytro_tech", "katya_support"]
    },
    "sla_minutes": {
      "type": "integer",
      "enum": [15, 120, 1440, 2880]
    },
    "sla_deadline": {
      "type": "string",
      "format": "date-time",
      "description": "Розрахований дедлайн відповіді: timestamp створення тікета + sla_minutes, у форматі ISO 8601"
    },
    "status": {
      "type": "string",
      "enum": ["open", "in_progress", "escalated", "resolved"],
      "description": "Поточний статус тікета; для нового тікета завжди open"
    },
    "thread_link": {
      "type": ["string", "null"],
      "format": "uri",
      "description": "Посилання на оригінальний email-лист/тред у поштовому клієнті (mailto: лінк, web-link на лист в Gmail/Outlook, або internal message ID). null, якщо посилання не передане в контексті"
    },
    "reasoning": {
      "type": "string",
      "description": "3 речення обґрунтування пріоритету за 3 вимірами"
    },
    "summary": {
      "type": "string",
      "description": "1 речення, про що тікет"
    },
    "customer_sentiment": {
      "type": "string",
      "enum": ["positive", "neutral", "frustrated", "angry"]
    }
  },
  "required": ["category", "priority", "owner", "sla_minutes", "sla_deadline", "status", "thread_link", "reasoning", "summary", "customer_sentiment"]
}
